import React, { useState, useEffect } from 'react';
import { View, Text, Button } from 'react-native';
import axios from 'axios';

const App = () => {
  const [token, setToken] = useState(null);
  const [refreshToken, setRefreshToken] = useState(null);

  const clientId = 'your_client_id_here';
  const clientSecret = 'your_client_secret_here';
  const authServerUrl = 'https://your-auth-server.com/oauth/token';

  useEffect(() => {
    if (!token) {
      authenticate();
    }
  }, [token]);

  const authenticate = async () => {
    try {
      const response = await axios.post(
        authServerUrl,
        `grant_type=authorization_code&code=${getCode()}&redirect_uri=https://your-app.com/callback`,
        {
          headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
          },
          auth: {
            username: clientId,
            password: clientSecret,
          },
        }
      );
      setToken(response.data.access_token);
      setRefreshToken(response.data.refresh_token);
    } catch (error) {
      console.error(error);
    }
  };

  const getCode = async () => {
    try {
      const response = await axios.get('https://your-auth-server.com/oauth/authorize', {
        params: {
          client_id: clientId,
          redirect_uri: 'https://your-app.com/callback',
          response_type: 'code',
          scope: 'your_scope_here',
        },
      });
      return response.data.code;
    } catch (error) {
      console.error(error);
    }
  };

  const refreshToken = async () => {
    try {
      const response = await axios.post(
        authServerUrl,
        `grant_type=refresh_token&refresh_token=${refreshToken}`,
        {
          headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
          },
          auth: {
            username: clientId,
            password: clientSecret,
          },
        }
      );
      setToken(response.data.access_token);
    } catch (error) {
      console.error(error);
    }
  };

  const handleButtonPress = async () => {
    if (!token) {
      authenticate();
    } else {
      refreshToken();
    }
  };

  return (
    <View>
      <Text>Authenticated: {token ? 'Yes' : 'No'}</Text>
      <Button title="Authenticate" onPress={handleButtonPress} />
    </View>
  );
};

export default App;